'use client'
import { cn, Slot } from '@cascivo/core'
import { forwardRef, type ButtonHTMLAttributes, type ReactNode } from 'react'
import styles from './icon-button.module.css'

export interface IconButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  /** Accessible name for the icon-only control. Required — there is no visible text. */
  label: string
  /** The icon to render. Alias for `children`. */
  icon?: ReactNode
  size?: 'sm' | 'md' | 'lg'
  variant?: 'ghost' | 'outline' | 'filled'
  /** Render the single child element instead of a `<button>` (composition). */
  asChild?: boolean
}

export const IconButton = forwardRef<HTMLButtonElement, IconButtonProps>(function IconButton(
  { label, icon, size = 'md', variant = 'ghost', asChild = false, className, children, ...props },
  ref,
) {
  const Comp = asChild ? Slot : 'button'
  return (
    <Comp
      type={asChild ? undefined : 'button'}
      aria-label={label}
      data-size={size}
      data-variant={variant}
      className={cn(styles['iconButton'], className as string | undefined)}
      ref={ref as never}
      {...(props as Record<string, unknown>)}
    >
      {children ?? icon}
    </Comp>
  )
})

@layer cascivo.component {
  .iconButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    aspect-ratio: 1;
    flex-shrink: 0;
    padding: 0;
    font-family: var(--cascivo-font-sans);
    line-height: var(--cascivo-leading-none);
    cursor: pointer;
    border: 1px solid transparent;
    border-radius: var(--cascivo-button-radius, var(--cascivo-radius-control));
    background-color: transparent;
    color: var(--cascivo-color-text);
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      pointer-events: none;
    }

    /* Sizes — square, driven by control-height tokens */
    &[data-size='sm'] {
      block-size: var(--cascivo-control-height-sm);
      inline-size: var(--cascivo-control-height-sm);
      font-size: var(--cascivo-text-sm);
    }

    &[data-size='md'] {
      block-size: var(--cascivo-control-height-md);
      inline-size: var(--cascivo-control-height-md);
      font-size: var(--cascivo-text-base);
    }

    &[data-size='lg'] {
      block-size: var(--cascivo-control-height-lg);
      inline-size: var(--cascivo-control-height-lg);
      font-size: var(--cascivo-text-lg);
    }

    /* Variants */
    &[data-variant='ghost'] {
      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-bg-subtle);
      }
    }

    &[data-variant='outline'] {
      border-color: var(--cascivo-color-border);
      background-color: var(--cascivo-color-surface);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-bg-subtle);
      }
    }

    &[data-variant='filled'] {
      background-color: var(--cascivo-color-primary);
      color: var(--cascivo-color-primary-fg);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-primary-hover);
      }

      &:active:not(:disabled) {
        background-color: var(--cascivo-color-primary-active);
      }
    }
  }
}

@media (forced-colors: active) {
  .iconButton {
    border: 1px solid ButtonText;
  }

  .iconButton:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }

  .iconButton:disabled {
    border-color: GrayText;
    color: GrayText;
  }
}
